@Test public void handlesTextareaWithMixedCaseClosingTag() {
    Document doc = Jsoup.parse("<textarea>content</TextArea>");
    Element textarea = doc.select("textarea").first();
    assertEquals("content", textarea.text());
}

@Test public void handlesTitleWithAllUppercaseClosingTag() {
    Document doc = Jsoup.parse("<title>My Title</TITLE>");
    assertEquals("My Title", doc.title());
}

@Test public void handlesTextareaWithUppercaseClosingTag() {
    Document doc = Jsoup.parse("<textarea>some text</TEXTAREA><p>after</p>");
    Element textarea = doc.select("textarea").first();
    assertEquals("some text", textarea.text());
    assertEquals("after", doc.select("p").first().text());
}
